FormScriptItem.Script:
var docIDs3 = VV.Form.Global.GetSelectRows("RRC3")

if (docIDs3.length > 0) {
    VV.Form.SetFieldValue('txt3', docIDs3);
}else{
    VV.Form.SetFieldValue('txt3', "No RRCs selected");
}

var docIDs1 = VV.Form.Global.GetSelectRows("RRC1")

if (docIDs1.length > 0) {
    VV.Form.SetFieldValue('txt1', docIDs1);
}else{
    VV.Form.SetFieldValue('txt1', "No RRCs selected");
}
